 {"id":"frankenpandas-rox","title":"Add DataFrame drop_columns packet conformance coverage","description":"Testing-conformance fallback audit found DataFrame::drop_columns implemented in fp-frame but no dataframe_drop_columns fixture operation or packet coverage. Add pandas-oracle-backed FP-P2D fixtures for dropping one column, dropping multiple columns with preserved order, dropping all columns while preserving the index, and missing-column rejection so pandas df.drop(columns=...) parity is frozen around column selection and error semantics.","status":"closed","priority":2,"issue_type":"task","created_at":"2026-04-18T05:38:42.992636339Z","created_by":"ubuntu","updated_at":"2026-04-18T05:44:20.855435778Z","closed_at":"2026-04-18T05:44:20.853547785Z","close_reason":"Completed DataFrame drop_columns conformance packet coverage","source_repo":".","compaction_level":0,"original_size":0,"labels":["columns","conformance","dataframe"]}
